1	import { describe, it, expect } from "vitest";
2	import { scale } from "./pixel-art-scaler.js";
3	
4	describe("Pixel Art Scaler", () => {
5	  it("should return empty array for empty image", () => {
6	    expect(scale([], 2)).toEqual([]);
7	  });
8	  it("should return single pixel unchanged when scale factor is 1", () => {
9	    expect(scale(["#"], 1)).toEqual(["#"]);
10	  });
11	  it("should scale single pixel both horizontally and vertically by 2", () => {
12	    expect(scale(["#"], 2)).toEqual(["##", "##"]);
13	  });
14	  it("should scale 2x2 grid by factor of 2", () => {
15	    expect(scale(["#.", ".#"], 2)).toEqual(["##..", "##..", "..##", "..##"]);
16	  });
17	  it("should scale 1x3 row by factor of 2", () => {
18	    expect(scale(["#.#"], 2)).toEqual(["##..##", "##..##"]);
19	  });
20	  it("should scale 3x1 column by factor of 2", () => {
21	    expect(scale(["#", ".", "#"], 2)).toEqual(["##", "##", "..", "..", "##", "##"]);
22	  });
23	  it("should scale 2x3 grid by factor of 3", () => {
24	    expect(scale(["#.", ".."], 3)).toEqual(["###...", "###...", "###...", "......", "......", "......"]);
25	  });
26	});
