1	function scaleHorizontally(line: string, factor: number): string {
2	  return line.split('').map(char => char.repeat(factor)).join('');
3	}
4	
5	function scaleVertically(image: string[], factor: number): string[] {
6	  return image.flatMap(line => Array(factor).fill(line));
7	}
8	
9	export function scale(image: string[], factor: number): string[] {
10	  if (image.length === 0) {
11	    return [];
12	  }
13	  const horizontallyScaled = image.map(line => scaleHorizontally(line, factor));
14	  return scaleVertically(horizontallyScaled, factor);
15	}
